   567→ * neither worker-src nor child-src is present in a CSP.
   568→ */
   569→class nsCSPScriptSrcDirective : public nsCSPDirective {
   570→ public:
   571→  explicit nsCSPScriptSrcDirective(CSPDirective aDirective);
