   612→  ~nsBlockAllMixedContentDirective();
   613→
   614→  bool permits(CSPDirective aDirective, nsILoadInfo* aLoadInfo, nsIURI* aUri,
   615→               bool aWasRedirected, bool aReportOnly,
   616→               bool aUpgradeInsecure) const override {
