#ifndef mozilla_dom_CSPEvalChecker_h
#define mozilla_dom_CSPEvalChecker_h

#include "nsString.h"

struct JSContext;
class nsGlobalWindowInner;

namespace mozilla::dom {

class WorkerPrivate;

class CSPEvalChecker final {
